  ('disabled-57f41407-moex-00005', 'disabled-57f41407', 'disabled-57f41407-moex-114-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '下列成語運用，何者最適切？', '["占社會最大多數的基層勞工，對臺灣經濟發展的貢獻「一語不發」", "新冠疫情漸趨流感化後，令人有脫離苦海、「如釋重負」的感覺", "時間飛逝，轉眼已畢業數月，老師的教誨言猶在耳，「音容宛在」", "因疫情使餐飲生意大多「門庭若市」，這家餐廳的業績卻逆勢成長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "14ca14cfc045", "answer_pdf_sha1": "067ca9634128", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
